def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = ratio ** 3
        elif 0.5 < ratio <= 1:
            priorities[i] = -np.log(1 - ratio + 1e-9)
        else:
            sum_val = 0
            for j in range(1, int(capacity) + 1):
                sum_val += (ratio ** j) / j
            priorities[i] = sum_val if sum_val != 0 else 1
        if capacity < item:
            priorities[i] += (item - capacity) * 10
    return priorities
